function SqlRunner() {
  const [query, setQuery] = React.useState('SELECT * FROM users WHERE active = true;');
  const [results, setResults] = React.useState(null);
  const [running, setRunning] = React.useState(false);

  const mockData = {
    'SELECT * FROM users WHERE active = true;': {
      columns: ['id', 'name', 'email', 'active'],
      rows: [
        [1, 'Alice Johnson', 'alice@example.com', true],
        [3, 'Charlie Kim', 'charlie@example.com', true],
        [5, 'Eva Martinez', 'eva@example.com', true]
      ]
    },
    'SELECT * FROM users;': {
      columns: ['id', 'name', 'email', 'active'],
      rows: [
        [1, 'Alice Johnson', 'alice@example.com', true],
        [2, 'Bob Smith', 'bob@example.com', false],
        [3, 'Charlie Kim', 'charlie@example.com', true],
        [4, 'Diana Lee', 'diana@example.com', false],
        [5, 'Eva Martinez', 'eva@example.com', true]
      ]
    },
    'SELECT * FROM orders;': {
      columns: ['order_id', 'user_id', 'total', 'status'],
      rows: [
        [101, 1, 249.99, 'shipped'],
        [102, 2, 89.50, 'pending'],
        [103, 1, 19.99, 'delivered'],
        [104, 3, 150.00, 'shipped']
      ]
    }
  };

  function runQuery() {
    setRunning(true);
    setTimeout(() => {
      const key = Object.keys(mockData).find(k => k.toLowerCase().trim() === query.toLowerCase().trim());
      if (key) {
        setResults({ ...mockData[key], duration: 12 });
      } else {
        setResults({ columns: [], rows: [], duration: 8, empty: true });
      }
      setRunning(false);
    }, 400);
  }

  const sampleQueries = Object.keys(mockData);

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#fff', borderRadius: 12, height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <h2 style={{ margin: '0 0 12px 0', fontSize: 18, color: '#1a1a1a' }}>SQL Runner</h2>
      <div style={{ marginBottom: 8, display: 'flex', gap: 6, flexWrap: 'wrap' }}>
        {sampleQueries.map((q, i) => (
          <button
            key={i}
            onClick={() => setQuery(q)}
            style={{ padding: '4px 10px', borderRadius: 12, border: '1px solid #ddd', background: '#f3f4f6', fontSize: 11, cursor: 'pointer', color: '#374151' }}
          >
            {q.length > 30 ? q.slice(0, 30) + '...' : q}
          </button>
        ))}
      </div>
      <textarea
        value={query}
        onChange={e => setQuery(e.target.value)}
        style={{ width: '100%', height: 70, padding: 10, borderRadius: 6, border: '1px solid #ddd', fontSize: 12, fontFamily: 'monospace', resize: 'none', boxSizing: 'border-box', marginBottom: 10 }}
        placeholder="Enter SQL query..."
      />
      <button
        onClick={runQuery}
        disabled={running}
        style={{ padding: '8px 16px', borderRadius: 6, border: 'none', background: running ? '#9ca3af' : '#2563eb', color: '#fff', fontSize: 13, cursor: running ? 'not-allowed' : 'pointer', marginBottom: 12, alignSelf: 'flex-start' }}
      >
        {running ? 'Running...' : 'Run Query'}
      </button>
      <div style={{ flex: 1, overflow: 'auto', border: '1px solid #e5e7eb', borderRadius: 6 }}>
        {results && (
          <div style={{ height: '100%' }}>
            {!results.empty ? (
              <>
                <div style={{ padding: '8px 12px', fontSize: 11, color: '#6b7280', borderBottom: '1px solid #e5e7eb', background: '#f9fafb' }}>
                  {results.rows.length} row{results.rows.length !== 1 ? 's' : ''} · {results.duration}ms
                </div>
                <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
                  <thead>
                    <tr>
                      {results.columns.map((col, i) => (
                        <th key={i} style={{ padding: '8px 12px', textAlign: 'left', background: '#f3f4f6', borderBottom: '1px solid #e5e7eb', fontWeight: 600, color: '#374151', whiteSpace: 'nowrap' }}>{col}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {results.rows.map((row, ri) => (
                      <tr key={ri} style={{ background: ri % 2 === 0 ? '#fff' : '#f9fafb' }}>
                        {row.map((cell, ci) => (
                          <td key={ci} style={{ padding: '8px 12px', borderBottom: '1px solid #e5e7eb', color: '#4b5563', fontFamily: 'monospace', fontSize: 12, whiteSpace: 'nowrap' }}>{String(cell)}</td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </>
            ) : (
              <div style={{ padding: 20, textAlign: 'center', color: '#999', fontSize: 13 }}>No results for this query. Try a sample query above.</div>
            )}
          </div>
        )}
        {!results && <div style={{ padding: 20, textAlign: 'center', color: '#999', fontSize: 13 }}>Run a query to see results.</div>}
      </div>
    </div>
  );
}
render(<SqlRunner/>);
